export function getFilesToProcess(
  sourceDir: string,
  state: GraphState
): string[] {
  if (!fs.existsSync(sourceDir)) {
    return [];
  }

  const filesToProcess: string[] = [];

  // Recursive function to traverse directories
  function traverseDirectory(dir: string) {
    const entries = fs.readdirSync(dir);
    for (const entry of entries) {
      const fullPath = path.join(dir, entry);
      const stat = fs.statSync(fullPath);
      if (stat.isDirectory()) {
        // Recurse into subdirectories
        traverseDirectory(fullPath);
      } else if (stat.isFile() && entry.endsWith('.md')) {
        if (hasFileChanged(fullPath, state)) {
          filesToProcess.push(fullPath);
        }
      }
    }
  }

  traverseDirectory(sourceDir);
  return filesToProcess;
}

async waitForEventsAfterAction(
  action: () => Promise<unknown>,
  options?: {timeout?: number},
): Promise<void> {
  const navigationFinished = this.waitForNavigationStarted()
    .then(navigationStated => {
      if (navigationStated) {
        return this.#page.waitForNavigation({
          timeout: options?.timeout ?? this.#navigationTimeout,
          signal: this.#abortController.signal,
        });
      }
      return;
    })
    .catch(error => logger(error));
  try {
    await action();
  } catch (error) {
    // Clear up pending promises
    this.#abortController.abort();
    throw error;
  }
  try {
    await navigationFinished;
    // Wait for stable dom after navigation so we execute in
    // the correct context
    await this.waitForStableDom();
  } catch (error) {
    logger(error);
  } finally {
    this.#abortController.abort();
  }
}

export function timingSafeEqual(a: string, b: string): boolean {
  if (a.length !== b.length) {
    return false;
  }
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

def _set_unincluded_data_to_nans(
    input_2d_data: np.ndarray,
    frames_with_reprojection_error: list,
    markers_with_reprojection_error: list,
    cameras_to_remove: list[list[int]],
) -> np.ndarray:
    data_to_reproject = input_2d_data.copy()
    for list_of_cameras, frame, marker in zip(
        cameras_to_remove,
        frames_with_reprojection_error,
