def _get_associated_indices(
    self,
    similarity_matrix: np.ndarray,
    min_similarity_thresh: float,
) -> tuple[list[tuple[int, int]], set[int], set[int]]:
    matched_indices = []
    n_tracks, n_detections = similarity_matrix.shape
    unmatched_tracks = set(range(n_tracks))
    unmatched_detections = set(range(n_detections))

    if n_tracks > 0 and n_detections > 0:
        row_indices, col_indices = linear_sum_assignment(
            similarity_matrix, maximize=True
        )
        for row, col in zip(row_indices, col_indices):
            if (
                similarity_matrix[row, col]
                >= min_similarity_thresh
            ):
                matched_indices.append((row, col))
                unmatched_tracks.remove(row)
                unmatched_detections.remove(col)

    return (
        matched_indices,
        unmatched_tracks,
        unmatched_detections,
    )

template <typename TArg>
void set_bits(TArg val) {
  size_t num = static_cast<size_t>(val) % bits_count_;
  bitset_[num >> 5] |= (1u << (num & 0x1f));
}

template <typename TArg, typename... TArgs>
void set_bits(TArg val, TArgs... vals) {
  this->set_bits(val);
  this->set_bits(vals...);
}

template <typename TArg>
bool test_bits(TArg val) const {
  size_t num = static_cast<size_t>(val) % bits_count_;
  return ((bitset_[num >> 5] & (1u << (num & 0x1f))) != 0);
}

template <typename TArg, typename... TArgs>
bool test_bits(TArg val, TArgs... vals) const {
  if (!this->test_bits(val)) {
    return false;
  }
  return this->test_bits(vals...);
}

bool pos_add(uint32_t i, llama_pos d) {
    assert(i < pos.size());
    assert(pos[i] != -1);

    seq_pos_rm(i);

    pos[i]   += d;
    shift[i] += d;

    has_shift = true;

