void add(const Self & to, Arena * arena)
{
    if (!to.data().has())
        return;

    if (data().isEqualTo(to.data()))
        counter += to.counter;
    else if (!data().has() || counter < to.counter)
    {
        data().set(to.data(), arena);
        counter = to.counter - counter;
    }
    else
        counter -= to.counter;
}

@staticmethod
def _convert_sandbox_status(
    api_status: ApiSandboxStatus | None,
) -> SandboxStatus:
    """Convert API SandboxStatus to domain SandboxStatus."""
    from datetime import datetime
    from opensandbox.api.lifecycle.types import Unset
    from opensandbox.models.sandboxes import SandboxStatus
    if api_status is None:
        return SandboxStatus(
            state="Unknown",
            reason=None,
            message=None,
            last_transition_at=None,
        )
    reason: str | None = None
    if hasattr(api_status, "reason"):
        reason_val = api_status.reason
        if isinstance(reason_val, str):
            reason = reason_val
    message: str | None = None
    if hasattr(api_status, "message"):
        message_val = api_status.message
        if isinstance(message_val, str):
            message = message_val
    last_transition_at: datetime | None = None
    if hasattr(api_status, "last_transition_at"):
        lta_val = api_status.last_transition_at
        if isinstance(lta_val, datetime):
            last_transition_at = lta_val
        elif isinstance(lta_val, Unset) or lta_val is None:
            last_transition_at = None
    return SandboxStatus(
        state=api_status.state,
        reason=reason,
        message=message,
        last_transition_at=last_transition_at,
    )

def _chunk_tokens(
    self,
    tokens: Union[torch.Tensor, List[int]],
) -> Iterable[Union[torch.Tensor, List[int]]]:
    save_unfull_chunk = (
        self.config.save_unfull_chunk
        if self.config is not None
        else True
    )
    end = (
        len(tokens)
        if save_unfull_chunk
        else (len(tokens) - len(tokens) % self.chunk_size)
    )
    for i in range(0, end, self.chunk_size):
        yield tokens[i : i + self.chunk_size]

void StateLogger::pushToRing_(const Entry& e) {
    std::lock_guard<std::mutex> lock(ring_mutex_);
    if (size_ < capacity_) {
        size_t pos = (start_ + size_) % capacity_;
        ring_[pos] = e;
        size_ += 1;
    } else {
        // Overwrite oldest
        ring_[start_] = e;
        start_ = (start_ + 1) % capacity_;
    }
}

void depth_first_traversal(
    std::function<void(array)> callback,
    const std::vector<array>& outputs) {
  std::function<void(const array&)> recurse;
  std::unordered_set<std::uintptr_t> cache;
  recurse = [&](const array& x) {
    auto id = x.id();
    if (cache.find(id) != cache.end()) {
      return;
    }
    cache.insert(id);
    for (auto& s : x.siblings()) {
      cache.insert(s.id());
    }
    for (auto& in : x.inputs()) {
      recurse(in);
    }
    callback(x);
  };
  for (auto& o : outputs) {
    recurse(o);
  }
}

function sendCommandToFigma(
  command: FigmaCommand,
  params: unknown = {},
  timeoutMs: number = 30000
): Promise<unknown> {
  return new Promise((resolve, reject) => {
    if (!ws || ws.readyState !== WebSocket.OPEN) {
      connectToFigma();
      reject(new Error(
        "Not connected to Figma. Attempting to connect..."
      ));
      return;
    }

    const requiresChannel = command !== "join";
    if (requiresChannel && !currentChannel) {
      reject(new Error(
        "Must join a channel before sending commands"
      ));
      return;
    }

    const id = uuidv4();
    const request = {
      id,
      type: command === "join" ? "join" : "message",
      ...(command === "join"
        ? { channel: (params as any).channel }
        : { channel: currentChannel }),
      message: {
        id,
        command,
        params: {
          ...(params as any),
          commandId: id,
        },
      },
    };

    const timeout = setTimeout(() => {
      if (pendingRequests.has(id)) {
        pendingRequests.delete(id);
        reject(
          new Error('Request to Figma timed out')
        );
      }
    }, timeoutMs);

    pendingRequests.set(id, {
      resolve,
      reject,
      timeout,
      lastActivity: Date.now()
    });

    ws.send(JSON.stringify(request));
  });
}

function extractChatflowId(
  url: string
): string | null {
  try {
    const urlParts = url.split('/')
    const slug = extractSlugFromUrl(url)
    if (!slug) return null
    const slugIndex = urlParts.indexOf(slug)
    if (
      slugIndex !== -1 &&
      urlParts.length > slugIndex + 1
    ) {
      const chatflowId = urlParts[slugIndex + 1]
      return chatflowId.split('?')[0]
    }
    return null
  } catch (error) {
    logger.error(
      'Error extracting chatflow ID from URL:',
      error
    )
    return null
  }
}

def weight_quant(self, weight):
    dtype = weight.dtype
    weight = weight.float()
    s = 1 / weight.abs().mean().clamp(min=1e-5)
    result = (weight * s).round().clamp(-1, 1) / s
    return result.type(dtype)

