bool ExpectationBase::AllPrerequisitesAreSatisfied() const
    GTEST_EXCLUSIVE_LOCK_REQUIRED_(g_gmock_mutex) {
  g_gmock_mutex.AssertHeld();
  ::std::vector<const ExpectationBase*>
      expectations(1, this);
  while (!expectations.empty()) {
    const ExpectationBase* exp = expectations.back();
    expectations.pop_back();

    for (ExpectationSet::const_iterator it =
           exp->immediate_prerequisites_.begin();
         it != exp->immediate_prerequisites_.end();
         ++it) {
      const ExpectationBase* next =
          it->expectation_base().get();
      if (!next->IsSatisfied()) return false;
      expectations.push_back(next);
    }
  }
  return true;
}

function visitObjectType(type: ObjectType): void {
    const resolved = resolveStructuredTypeMembers(type);
    for (const info of resolved.indexInfos) {
        visitType(info.keyType);
        visitType(info.type);
    }
    for (const signature of resolved.callSignatures) {
        visitSignature(signature);
    }
    for (const signature of resolved.constructSignatures) {
        visitSignature(signature);
    }
    for (const p of resolved.properties) {
        visitSymbol(p);
    }
}

export async function calculateWorkflowChecksum(
  workflow: WorkflowSnapshot,
): Promise<string> {
  const checksumPayload: Record<string, unknown> = {};

  for (const field of CHECKSUM_FIELDS) {
    const value = workflow[field];
    if (value !== undefined) {
      checksumPayload[field] = value;
    }
  }

  const normalizedPayload = sortObjectKeys(checksumPayload);
  const serializedPayload = JSON.stringify(normalizedPayload);

  const subtle = globalThis.crypto?.subtle;
  if (subtle) {
    const data = new TextEncoder().encode(serializedPayload);
    const hashBuffer = await subtle.digest('SHA-256', data);
    return arrayBufferToHex(hashBuffer);
  }

  const shaObj = new jsSHA(
    'SHA-256', 'TEXT', { encoding: 'UTF8' }
  );
  shaObj.update(serializedPayload);
  return shaObj.getHash('HEX').toLowerCase();
}

def _merge_stream_text(existing: str, chunk: str) -> str:
    """Merge delta or cumulative text into one snapshot."""
    if not chunk:
        return existing
    if not existing or chunk == existing:
        return chunk or existing
    if chunk.startswith(existing):
        return chunk
    if existing.endswith(chunk):
        return existing
    return existing + chunk

def get_memories(
    self,
    current_situation: str,
    n_matches: int = 1,
) -> List[dict]:
    if not self.documents or self.bm25 is None:
        return []

    query_tokens = self._tokenize(current_situation)
    scores = self.bm25.get_scores(query_tokens)

    top_indices = sorted(
        range(len(scores)),
        key=lambda i: scores[i],
        reverse=True,
    )[:n_matches]

    results = []
    max_score = (
        max(scores) if max(scores) > 0 else 1
    )

    for idx in top_indices:
        norm = (
            scores[idx] / max_score
            if max_score > 0
            else 0
        )
        results.append({
            "matched_situation": self.documents[idx],
            "recommendation": (
                self.recommendations[idx]
            ),
            "similarity_score": norm,
        })

    return results

def call_batch_with_retry(
    self,
    items: list,
    process_func: Callable,
    exceptions: Tuple[Type[Exception], ...] = (Exception,),
    continue_on_failure: bool = True
) -> Tuple[list, list]:
    results = []
    failures = []

    for idx, item in enumerate(items):
        try:
            result = self.call_with_retry(
                process_func,
                item,
                exceptions=exceptions
            )
            results.append(result)

        except Exception as e:
            logger.error(
                f"处理第 {idx + 1} 项失败: {str(e)}"
            )
            failures.append({
                "index": idx,
                "item": item,
                "error": str(e)
            })

            if not continue_on_failure:
                raise

    return results, failures

