bool PosePredictionModel::predict_left_update(
    Isometry3T& update,
    int64_t timestamp_ns,
    Isometry3T* latest_pose) const {
  assert(poses_.size() == timestamps_ns_.size());

  if (poses_.size() < 2) {
    return false;
  }

  assert(poses_.size() == 2);

  // No interpolation: we only want to predict.
  if (timestamp_ns < timestamps_ns_.back()) {
    assert(false);
    return false;
  }

  const int64_t previous_dt_ns =
      timestamps_ns_.back() -
      timestamps_ns_.front();
  const int64_t dt_ns =
      timestamp_ns - timestamps_ns_.back();
  const float factor =
      static_cast<float>(dt_ns) /
      static_cast<float>(previous_dt_ns);

  const Isometry3T previous_update =
      poses_.back() *
      poses_.front().inverse();
  Vector6T diff;
  ::Log(diff, previous_update);
  ::Exp(update, diff * factor);

  if (latest_pose) {
    *latest_pose = poses_.back();
  }

  return true;
}

def _get_fields_dict(func: Callable) -> Dict:
  param_signature = dict(
      inspect.signature(func).parameters)
  fields_dict = {
      name: (
          (
              param.annotation
              if param.annotation
              != inspect.Parameter.empty
              else Any
          ),
          pydantic.Field(
              default=(
                  param.default
                  if param.default
                  != inspect.Parameter.empty
                  else pydantic_fields.PydanticUndefined
              ),
              description=None,
          ),
      )
      for name, param in param_signature.items()
      if param.kind
      in (
          inspect.Parameter.POSITIONAL_OR_KEYWORD,
          inspect.Parameter.KEYWORD_ONLY,
          inspect.Parameter.POSITIONAL_ONLY,
      )
  }
  return fields_dict

def _acquire_permission(self) -> None:
    with self._lock:
        if self._state == "open":
            elapsed = (
                time.time() - self._last_failure_time
            )
            if elapsed >= self.reset_timeout:
                self._state = "half-open"

        if self._state == "open":
            raise self.CircuitBreakerOpen(
                f"Circuit breaker '{self.name}' is open"
                " -- call rejected"
