export function createTemplateNodeMap({
    ast,
    filename,
    branchId,
}: {
    ast: T.File;
    filename: string;
    branchId: string;
}): Map<string, TemplateNode> {
    const mapping = new Map<string, TemplateNode>();
    const componentStack: string[] = [];
    const dynamicTypeStack: DynamicType[] = [];

    traverse(ast, {
        FunctionDeclaration: {
            enter(path) {
                if (!path.node.id) return;
                componentStack.push(path.node.id.name);
            },
            exit() { componentStack.pop(); },
        },
        VariableDeclaration: {
            enter(path) {
                const decl = path.node.declarations[0]?.id;
                if (!decl || !t.isIdentifier(decl)) return;
                componentStack.push(decl.name);
            },
            exit() { componentStack.pop(); },
        },
        CallExpression: {
            enter(path) {
                if (isNodeElementArray(path.node)) {
                    dynamicTypeStack.push(DynamicType.ARRAY);
                }
            },
            exit(path) {
                if (isNodeElementArray(path.node)) {
                    dynamicTypeStack.pop();
                }
            },
        },
        ConditionalExpression: {
            enter() {
                dynamicTypeStack.push(
                    DynamicType.CONDITIONAL,
                );
            },
            exit() { dynamicTypeStack.pop(); },
        },
        JSXElement(path) {
            if (isReactFragment(
                path.node.openingElement,
            )) return;

            const existingOid = getExistingOid(
                path.node.openingElement.attributes,
            );
            if (!existingOid) return;

            const newTemplateNode = createTemplateNode(
                path,
                branchId,
                filename,
                componentStack,
                getDynamicTypeInfo(path),
                getCoreElementInfo(path),
            );
            mapping.set(existingOid.value, newTemplateNode);
        },
    });
    return mapping;
}

async function runWithConcurrencyLimit(
  thunks: Array<() => Promise<VulnExploitPipelineResult>>,
  limit: number,
): Promise<PromiseSettledResult<VulnExploitPipelineResult>[]> {
  const results: PromiseSettledResult<
    VulnExploitPipelineResult
  >[] = [];
  const inFlight = new Set<Promise<void>>();

  for (const thunk of thunks) {
    const slot = thunk()
      .then(
        (value) => {
          results.push({ status: 'fulfilled', value });
        },
        (reason: unknown) => {
          results.push({ status: 'rejected', reason });
        },
      )
      .finally(() => {
        inFlight.delete(slot);
      });

    inFlight.add(slot);

    if (inFlight.size >= limit) {
      await Promise.race(inFlight);
    }
  }

  await Promise.allSettled(inFlight);
  return results;
}

ss::future<>
batch_cache::background_reclaimer::reclaim_loop() {
    while (!_stopped) {
        auto units = std::max(
          _change.current(), size_t(1));
        co_await _change.wait(units);

        if (unlikely(_stopped)) {
            co_return;
        }

        if (!have_to_reclaim()) {
            continue;
        }

        auto free =
          ss::memory::stats().free_memory();

        if (free < _min_free_memory) {
            auto to_reclaim =
              _min_free_memory - free;
            _cache.reclaim(to_reclaim);
        }
    }
    co_return;
}

mjtNum mju_dotSparse2(
    const mjtNum* vec1, const int* ind1, int nnz1,
    const mjtNum* vec2, const int* ind2, int nnz2) {
  int i1 = 0, i2 = 0;
  mjtNum res = 0;

  if (!nnz1 || !nnz2) {
    return 0;
  }

  while (i1 < nnz1 && i2 < nnz2) {
    int adr1 = ind1[i1], adr2 = ind2[i2];

    if (adr1 == adr2) {
      res += vec1[i1++] * vec2[i2++];
    }
    else if (adr1 < adr2) {
      i1++;
    } else {
      i2++;
    }
  }

  return res;
}

