def _parse_response_as_model(
    self,
    content: str,
    response_type: Type[T]
) -> T:
    # Try direct JSON parsing first
    try:
        data = json.loads(content)
        return response_type.model_validate(data)
    except json.JSONDecodeError:
        pass

    # Try extracting from markdown code block
    json_pattern = r'```(?:json)?\s*([\s\S]+?)\s*```'
    match = re.search(json_pattern, content, re.DOTALL)
    if match:
        try:
            data = json.loads(match.group(1))
            return response_type.model_validate(data)
        except json.JSONDecodeError:
            pass

    # Try to find any JSON object in the text
    brace_start = content.find('{')
    brace_end = content.rfind('}')
    if brace_start != -1 and brace_end > brace_start:
        try:
            json_str = content[brace_start:brace_end + 1]
            data = json.loads(json_str)
            return response_type.model_validate(data)
        except json.JSONDecodeError:
            pass

    raise ValueError(
        f"Failed to parse LLM response as "
        f"{response_type.__name__}: "
        f"{content[:200]}..."
    )

const writeRel = (rel: GraphRelationship): void => {
  relationshipMap.set(rel.id, rel);
  let typeBucket = relationshipsByType.get(rel.type);
  if (typeBucket === undefined) {
    typeBucket = new Map();
    relationshipsByType.set(rel.type, typeBucket);
  }
  typeBucket.set(rel.id, rel);
  addToBucket(edgeIdsByNode, rel.sourceId, rel.id);
  if (rel.targetId !== rel.sourceId) {
    addToBucket(edgeIdsByNode, rel.targetId, rel.id);
  }
};

const deleteRel = (rel: GraphRelationship): void => {
  relationshipMap.delete(rel.id);
  const typeBucket = relationshipsByType.get(rel.type);
  if (typeBucket !== undefined) {
    typeBucket.delete(rel.id);
    if (typeBucket.size === 0) {
      relationshipsByType.delete(rel.type);
    }
  }
  removeFromBucket(edgeIdsByNode, rel.sourceId, rel.id);
  if (rel.targetId !== rel.sourceId) {
    removeFromBucket(
      edgeIdsByNode, rel.targetId, rel.id
    );
  }
};

function escapeSandboxPath(path: string): string {
  return path
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"');
}

export function buildDarwinSandboxProfile(
  sessionDir: string,
  options?: FilesystemIsolationOptions,
): string {
  const escapedRoot =
    escapeSandboxPath(resolve(sessionDir));
  const profileParts = [
    '(version 1)',
    '(deny default)',
    '(allow process*)',
    '(allow sysctl-read)',
    '(allow file-read*)',
    '(deny file-write*)',
    `(allow file-write* (subpath "${escapedRoot}"))`,
  ];

  if (options?.includeNetworkDeny) {
    profileParts.push('(deny network*)');
  }

  return profileParts.join(' ');
}

bool can_use_cache(
    json& messages,
    chat_template_type_t template_type)
{
  uint64_t check_sum_to_compare = 0;
  uint64_t new_checksum = 0;

  if (messages.size() > 2) {
    for (size_t i = 0; i < messages.size(); ++i) {
      const auto& msg = messages[i];
      const std::string role =
          msg.value("role", "");
      const std::string content =
          msg.value("content", "");
      bool has_tool_call =
          msg.contains("tool_calls");
      bool skip_this_message =
          (role == "tool") || has_tool_call;

      if (template_type ==
          chat_template_type_t::harmony) {
        skip_this_message = false;
      }

      if (skip_this_message) continue;

      if (i < messages.size() - 2)
        check_sum_to_compare =
          _calculate_checksum(
            content.data(),
            content.size(),
            check_sum_to_compare);

      new_checksum = _calculate_checksum(
          content.data(),
          content.size(),
          new_checksum);
    }

    if (checksum_ == check_sum_to_compare) {
      checksum_ = new_checksum;
      return true;
    } else {
      checksum_ = new_checksum;
      return false;
    }
  } else {
    return false;
  }
}

