        except BrokenProcessPool:
            _restart_pool(old_pool=pool)

def evaluate_capability_policy(
    graph: CapabilityGraph,
    context: PolicyContext,
) -> tuple[PolicyDecision, ...]:
    """Evaluate visible/executable capability decisions."""
    profile = _ROLE_PROFILES[context.session_role]
    decisions: list[PolicyDecision] = []

    for descriptor in graph.capabilities:
        reasons: list[str] = []
        visible = _is_mutation_allowed(descriptor, profile)
        executable = visible

        if visible and not _matches_role_selector(
            descriptor, profile
        ):
            visible = False
            executable = False
            reasons.append(
                f"{context.session_role.value} profile "
                f"does not include {descriptor.name}"
            )
        elif not visible:
            reasons.append(
                f"mutation_class "
                f"{descriptor.semantics.mutation_class.value}"
                f" exceeds {context.session_role.value} policy"
            )

        if descriptor.source_kind in (
            _NON_EXECUTABLE_SOURCE_KINDS
        ):
            executable = False
            reasons.append(
                f"{descriptor.source_kind} requires live "
                f"provider discovery before execution"
            )

        decisions.append(
            PolicyDecision(
                stable_id=descriptor.stable_id,
                name=descriptor.name,
                visible=visible,
                executable=executable,
                approval_class=(
                    descriptor.semantics.approval_class
                ),
                reasons=tuple(reasons),
            )
        )

    return tuple(decisions)

export function parseNode(
  nodeData: RawDomTreeNode,
  parent: DOMElementNode | null = null,
): DOMBaseNode | null {
  if (!nodeData) return null;

  if ('type' in nodeData) {
    return new DOMTextNode(
      nodeData.text,
      nodeData.isVisible,
      parent,
    );
  }

  const tagName = nodeData.tagName;
  const viewportCoordinates =
    nodeData.viewportCoordinates;
  const pageCoordinates = nodeData.pageCoordinates;
  const viewportInfo = nodeData.viewportInfo;

  const elementNode = new DOMElementNode({
    tagName: tagName,
    xpath: nodeData.xpath,
    cssSelector: nodeData.cssSelector,
    attributes: nodeData.attributes ?? {},
    children: [],
    isVisible: nodeData.isVisible ?? false,
    isInteractive: nodeData.isInteractive ?? false,
    isTopElement: nodeData.isTopElement ?? false,
    highlightIndex: nodeData.highlightIndex,
    viewportCoordinates: viewportCoordinates ?? undefined,
    pageCoordinates: pageCoordinates ?? undefined,
    viewportInfo: viewportInfo ?? undefined,
    shadowRoot: nodeData.shadowRoot ?? false,
    parent,
  });

  const children: DOMBaseNode[] = [];
  for (const child of nodeData.children || []) {
    if (child !== null) {
      const childNode = parseNode(child, elementNode);
      if (childNode !== null) {
        children.push(childNode);
      }
    }
  }

  elementNode.children = children;
  return elementNode;
}

public async exchangeCode(
  code: string,
  codeVerifier: string
): Promise<CreateSessionResponse> {
  const data = this.pkceCodes.get(code);
  if (!data) {
    logger.warn(
      'OAuth PKCE code not found or already used'
    );
    throw new AppError(
      'Invalid or expired code',
      400,
      ERROR_CODES.INVALID_INPUT
    );
  }
  this.pkceCodes.delete(code);

  if (new Date() > data.expiresAt) {
    logger.warn('OAuth PKCE code expired', {
      provider: data.provider,
    });
    throw new AppError(
      'Invalid or expired code',
      400,
      ERROR_CODES.INVALID_INPUT
    );
  }

  const computedChallenge = crypto
    .createHash('sha256')
    .update(codeVerifier)
    .digest('base64url');

  if (computedChallenge !== data.codeChallenge) {
    logger.warn('PKCE validation failed', {
      provider: data.provider,
    });
    throw new AppError(
      'PKCE verification failed',
      400,
      ERROR_CODES.AUTH_UNAUTHORIZED
    );
  }

  const authService = AuthService.getInstance();
  const tokenManager = TokenManager.getInstance();
  const user = await authService.getUserSchemaById(
    data.userId
  );
  if (!user) {
    logger.error(
      'User not found during PKCE exchange',
      { userId: data.userId }
    );
    throw new AppError(
      'User not found',
      404,
      ERROR_CODES.NOT_FOUND
    );
  }

  const accessToken =
    tokenManager.generateAccessToken({
      sub: user.id,
      email: user.email,
      role: 'authenticated',
    });

  logger.info(
    'OAuth PKCE code successfully exchanged',
    { provider: data.provider }
  );
  return { user, accessToken };
}

static void updateColorVariable(
    CAnimatedVariable<CHyprColor>& av,
    const float POINTY,
    bool warp = false
) {
    if (warp || av.value() == av.goal()) {
        av.warp(true, false);
        return;
    }

    const auto& L1 = av.begun().asOkLab();
    const auto& L2 = av.goal().asOkLab();

    static const auto lerp = [](
        const float one,
        const float two,
        const float progress
    ) -> float {
        return one + ((two - one) * progress);
    };

    const Hyprgraphics::CColor lerped =
        Hyprgraphics::CColor::SOkLab{
            .l = lerp(L1.l, L2.l, POINTY),
            .a = lerp(L1.a, L2.a, POINTY),
            .b = lerp(L1.b, L2.b, POINTY),
        };

    av.value() = {
        lerped,
        lerp(av.begun().a, av.goal().a, POINTY)
    };
}

void iqk_sumrows_div(
    struct ggml_tensor * div,
    int ith, int nth) {
    auto src = div->src[0];
    GGML_ASSERT(src->type == GGML_TYPE_F32);
    GGML_ASSERT(div->type == GGML_TYPE_F32);

    int ne00  = src->ne[0];
    int nrows = ggml_nrows(src);
    int npt   = (nrows + nth - 1)/nth;
    int first = ith*npt;
    int last  = std::min(first + npt, nrows);
    if (last < first) return;

    for (int ir = first; ir < last; ++ir) {
        auto values = (const float *)(
            (const char *)src->data
            + ir*src->nb[1]);
        float sum = 0;
        for (int j = 0; j < ne00; ++j)
            sum += values[j];
        float norm = sum > 0 ? 1/sum : 0.0f;
        auto result = (float *)(
            (char *)div->data
            + ir*div->nb[1]);
        for (int j = 0; j < ne00; ++j)
            result[j] = values[j]*norm;
    }
}

