def _resolve_dot_path(obj: Any, path: str) -> Any:
    """Resolve a dotted path like
    ``steps.specify.output.file`` against *obj*.

    Supports dict key access and list indexing
    (e.g., ``task_list[0]**).
    """
    parts = path.split(".")
    current = obj
    for part in parts:
        # Handle list indexing: name[0]
        idx_match = re.match(
            r"^([\w-]+)\[(\d+)\]$", part
        )
        if idx_match:
            key = idx_match.group(1)
            idx = int(idx_match.group(2))
            if isinstance(current, dict):
                current = current.get(key)
            else:
                return None
            if (
                isinstance(current, list)
                and 0 <= idx < len(current)
            ):
                current = current[idx]
            else:
                return None
        elif isinstance(current, dict):
            current = current.get(part)
        else:
            return None
        if current is None:
            return None
    return current

function getConditions(
  conditions: string[],
  isProduction: boolean,
  isRequire: boolean | undefined,
) {
  const resolvedConditions = conditions.map(
    (condition) => {
      if (condition === DEV_PROD_CONDITION) {
        return isProduction
          ? 'production'
          : 'development'
      }
      return condition
    },
  )

  if (isRequire) {
    resolvedConditions.push('require')
  } else {
    resolvedConditions.push('import')
  }

  return resolvedConditions
}

function rebuildSnapshot(): boolean {
  const out: QuerySnapshot = {
    __openui_loading: [],
    __openui_refetching: [],
    __openui_errors: [],
  };

  for (const [sid, q] of queries) {
    const entry = cache.get(q.cacheKey);
    if (entry && entry.data !== undefined) {
      out[sid] = entry.data;
    } else if (q.prevCacheKey) {
      const prev = cache.get(q.prevCacheKey);
      if (prev && prev.data !== undefined) {
        out[sid] = prev.data;
      } else {
        out[sid] = q.defaults;
      }
    } else {
      out[sid] = q.defaults;
    }
    if (q.loading) {
      out.__openui_loading.push(sid);
      if (q.everFetched) {
        out.__openui_refetching.push(sid);
      }
    }
    if (q.error) {
      out.__openui_errors.push(q.error);
    }
  }

  for (const [sid, m] of mutations) {
    out[sid] = m.result;
    if (m.error) out.__openui_errors.push(m.error);
  }

  try {
    const outJson = JSON.stringify(out);
    if (outJson === snapshotJson) return false;
    snapshot = out;
    snapshotJson = outJson;
  } catch {
    snapshot = out;
    snapshotJson = "";
  }
  return true;
}

int32_t KeyMap::findBestKey(
    const KeyEntryList &entryList,
    KeyModifierMask desiredState
) const
{
  // check for an item that can accommodate
  // the desiredState exactly
  for (int32_t i = 0;
       i < (int32_t)entryList.size(); ++i) {
    const KeyItem &item = entryList[i].back();
    if ((item.m_required & desiredState)
            == item.m_required &&
        (item.m_required & desiredState)
            == (item.m_sensitive & desiredState)) {
      return i;
    }
  }

  // choose the item that requires the fewest
  // modifier changes
  int32_t bestCount = 32;
  int32_t bestIndex = -1;
  for (int32_t i = 0;
       i < (int32_t)entryList.size(); ++i) {
    const KeyItem &item = entryList[i].back();
    KeyModifierMask change =
        ((item.m_required ^ desiredState)
         & item.m_sensitive);
    int32_t n = getNumModifiers(change);
    if (n < bestCount) {
      bestCount = n;
      bestIndex = i;
    }
  }

  return bestIndex;
}

/// Runs coroutines until there are no more in the queue
/// or until this thread gave up the queue in order to
/// run blocking code.
///
/// Must be called on the thread that called Claim().
void Scheduler::RunAndRelease() noexcept
{
    WI_ASSERT(!tls_Blocked);

    tls_SchedulerThread = true;
    std::unique_lock<std::shared_mutex> lock(m_Lock);
    while (!m_Queue.empty())
    {
        auto coroutine = m_Queue.front();
        m_Queue.pop();
        lock.unlock();
        coroutine.resume();
        if (tls_Blocked)
        {
            tls_Blocked = false;
            tls_SchedulerThread = false;
            return;
        }

        lock.lock();
    }

    WI_ASSERT(
        m_Queue.empty() || m_Running || m_ThreadEnqueued);

    m_Running = false;
    tls_SchedulerThread = false;
}

/// Called when the current thread may block for some
/// time. Gives up queue ownership, potentially
/// scheduling another thread to resume running
/// non-blocking code.
bool Scheduler::Block() noexcept
{
    if (!tls_SchedulerThread)
    {
        return false;
    }

    WI_ASSERT(!tls_Blocked);

    tls_Blocked = true;

    bool kick = false;

    {
        std::unique_lock<std::shared_mutex> lock(m_Lock);

        WI_ASSERT(m_Running);

        m_Running = false;
        if (!m_Queue.empty() && !m_ThreadEnqueued)
        {
            m_ThreadEnqueued = true;
            kick = true;
        }
    }

    if (kick)
    {
        m_Work->Submit();
    }

    return true;
}

def _install_strategy(cli):
    strategy = cli.get("install_strategy")
