    return strategy, handler(cli)

export function boundedEditDistance(
  a: string,
  b: string,
  maxDist: number
): number {
  if (a === b) return 0;
  const al = a.length;
  const bl = b.length;
  if (Math.abs(al - bl) > maxDist) return maxDist + 1;
  if (al === 0) return bl;
  if (bl === 0) return al;

  let prev = new Array<number>(bl + 1);
  let cur  = new Array<number>(bl + 1);
  for (let j = 0; j <= bl; j++) prev[j] = j;

  for (let i = 1; i <= al; i++) {
    cur[0] = i;
    let rowMin = cur[0]!;
    for (let j = 1; j <= bl; j++) {
      const cost =
        a.charCodeAt(i - 1) === b.charCodeAt(j - 1)
          ? 0 : 1;
      const insertion    = cur[j - 1]!  + 1;
      const deletion     = prev[j]!     + 1;
      const substitution = prev[j - 1]! + cost;
      cur[j] = Math.min(
        insertion, deletion, substitution
      );
      if (cur[j]! < rowMin) rowMin = cur[j]!;
    }
    if (rowMin > maxDist) return maxDist + 1;
    [prev, cur] = [cur, prev];
  }
  return prev[bl]!;
}

export function findCutPoint(
  entries: SessionEntry[],
  startIndex: number,
  endIndex: number,
  keepRecentTokens: number,
): CutPointResult {
  const cutPoints = findValidCutPoints(
    entries, startIndex, endIndex
  );

  if (cutPoints.length === 0) {
    return {
      firstKeptEntryIndex: startIndex,
      turnStartIndex: -1,
      isSplitTurn: false,
    };
  }

  let accumulatedTokens = 0;
  let cutIndex = cutPoints[0];

  for (let i = endIndex - 1; i >= startIndex; i--) {
    const entry = entries[i];
    if (entry.type !== "message") continue;

    const messageTokens =
      estimateTokens(entry.message);
    accumulatedTokens += messageTokens;

    if (accumulatedTokens >= keepRecentTokens) {
      for (let c = 0; c < cutPoints.length; c++) {
        if (cutPoints[c] >= i) {
          cutIndex = cutPoints[c];
          break;
        }
      }
      break;
    }
  }

  while (cutIndex > startIndex) {
    const prevEntry = entries[cutIndex - 1];
    if (prevEntry.type === "compaction") break;
    if (prevEntry.type === "message") break;
    cutIndex--;
  }

  const cutEntry = entries[cutIndex];
  const isUserMessage =
    cutEntry.type === "message" &&
    cutEntry.message.role === "user";
  const turnStartIndex = isUserMessage
    ? -1
    : findTurnStartIndex(
        entries, cutIndex, startIndex
      );

  return {
    firstKeptEntryIndex: cutIndex,
    turnStartIndex,
    isSplitTurn:
      !isUserMessage && turnStartIndex !== -1,
  };
}

