void AudioService::AudioInputTask() {
  while (true) {
    EventBits_t bits = xEventGroupWaitBits(
      event_group_,
      AS_EVENT_AUDIO_TESTING_RUNNING |
      AS_EVENT_WAKE_WORD_RUNNING |
      AS_EVENT_AUDIO_PROCESSOR_RUNNING,
      pdFALSE, pdFALSE, portMAX_DELAY);

    if (service_stopped_) break;

    if (audio_input_need_warmup_) {
      audio_input_need_warmup_ = false;
      vTaskDelay(pdMS_TO_TICKS(120));
      continue;
    }

    if (bits & AS_EVENT_AUDIO_TESTING_RUNNING) {
      int max = AUDIO_TESTING_MAX_DURATION_MS
                / OPUS_FRAME_DURATION_MS;
      if (audio_testing_queue_.size() >= max) {
        EnableAudioTesting(false);
        continue;
      }
      int samples =
        OPUS_FRAME_DURATION_MS * 16000 / 1000;
      std::vector<int16_t> data;
      if (ReadAudioData(data, 16000, samples)) {
        PushTaskToEncodeQueue(
          kAudioTaskTypeEncodeToTestingQueue,
          std::move(data));
        continue;
      }
    }

    if (bits & (AS_EVENT_WAKE_WORD_RUNNING |
                AS_EVENT_AUDIO_PROCESSOR_RUNNING)) {
      std::vector<int16_t> data;
      if (ReadAudioData(data, 16000, 160)) {
        if (bits & AS_EVENT_WAKE_WORD_RUNNING)
          wake_word_->Feed(data);
        if (bits & AS_EVENT_AUDIO_PROCESSOR_RUNNING)
          audio_processor_->Feed(std::move(data));
        continue;
      }
    }

    vTaskDelay(pdMS_TO_TICKS(10));
  }
}

def _extend_param(
    param: ParamHolder,
    concat_param: dict[str, list],
    count: int,
):
    if len(concat_param.keys()):
        assert param.key_list() == list(
            concat_param.keys()
        ), (
            f"param keys mismatch: "
            f"{param.key_list()} vs "
            f"{list(concat_param.keys())}"
        )
    for key, value in param.items():
        if key not in concat_param:
            concat_param[key] = []
        concat_param[key].extend([value] * count)

# Param replication must mirror the Rust kernel's element
# layout in `concat_tri`: rods first, then pure shells,
# then SOLID surface tris. `concat_tri_param` is read by
# the solver as a prefix-aligned slot for each tri, so
# any deviation from this order mis-pairs material
# parameters with their tris.
for name, obj in dyn_objects:
    stats = stats_by_name[name]
    rod_added = int(stats["rod_added"])
    tet_added = int(stats["tet_added"])
    if obj.obj_type == "rod" and rod_added:
        _extend_param(
            obj.param, concat_rod_param, rod_added
        )
    if tet_added:
        _extend_param(
            obj.param, concat_tet_param, tet_added
        )
# Pass A: pure shells.
for name, obj in dyn_objects:
    stats = stats_by_name[name]
    tri_added = int(stats["tri_added"])
    tet_added = int(stats["tet_added"])
    if tri_added and tet_added == 0:
        _extend_param(
            obj.param, concat_tri_param, tri_added
        )
# Pass B: SOLID surface triangles
# (objects carrying both tri and tet).
for name, obj in dyn_objects:
    stats = stats_by_name[name]
    tri_added = int(stats["tri_added"])
    tet_added = int(stats["tet_added"])
    if tri_added and tet_added:
        _extend_param(
            obj.param, concat_tri_param, tri_added
        )

export function mergeGraphUpdate(
  existingGraph: KnowledgeGraph,
  changedFilePaths: string[],
  newNodes: GraphNode[],
  newEdges: GraphEdge[],
  newCommitHash: string,
): KnowledgeGraph {
  const changedSet = new Set(changedFilePaths);

  // Collect IDs of nodes belonging to changed files
  const removedNodeIds = new Set(
    existingGraph.nodes
      .filter(
        (node) =>
          node.filePath !== undefined &&
          changedSet.has(node.filePath),
      )
      .map((node) => node.id),
  );

  // Keep nodes that don't belong to changed files
  const retainedNodes = existingGraph.nodes.filter(
    (node) => !removedNodeIds.has(node.id),
  );

  // Keep edges not touching removed nodes
  const retainedEdges = existingGraph.edges.filter(
    (edge) =>
      !removedNodeIds.has(edge.source) &&
      !removedNodeIds.has(edge.target),
  );

  return {
    ...existingGraph,
    project: {
      ...existingGraph.project,
      gitCommitHash: newCommitHash,
      analyzedAt: new Date().toISOString(),
    },
    nodes: [...retainedNodes, ...newNodes],
    edges: [...retainedEdges, ...newEdges],
  };
}

private processCompositeField(
  fieldMetadata: FlatFieldMetadata,
  fieldValue: any,
): Record<string, any> {
  const compositeType = compositeTypeDefinitions.get(
    fieldMetadata.type as CompositeFieldMetadataType,
  );

  if (!compositeType) {
    throw new Error(
      `Composite type definition not found` +
      ` for type: ${fieldMetadata.type}`,
    );
  }

  return Object.entries(fieldValue).reduce(
    (acc, [subFieldKey, subFieldValue]) => {
      if (subFieldKey === '__typename') return acc;

      const subFieldMetadata = compositeType.properties.find(
        (property) => property.name === subFieldKey,
      );

      if (!subFieldMetadata) {
        throw new Error(
          `Sub field metadata not found for` +
          ` composite type: ${fieldMetadata.type}`,
        );
      }

      acc[subFieldKey] = this.formatFieldValue(
        subFieldValue,
        subFieldMetadata.type,
      );

      return acc;
    },
    {} as Record<string, any>,
  );
}

bool TensorUtils::isTransposeRegion(
    const Tensor::InsideDescribe::Region& region) {
    int srcOne = -1, dstOne = -1;
    for (int i = 0; i < 3; i++) {
        if (region.src.stride[i] == 1
            && region.size[i] != 1) {
            if (srcOne >= 0) {
                return false;
            }
            srcOne = i;
        }
        if (region.dst.stride[i] == 1
            && region.size[i] != 1) {
            if (dstOne >= 0) {
                return false;
            }
            dstOne = i;
        }
    }
    return srcOne >= 0
        && dstOne >= 0
        && srcOne != dstOne;
}

// Returns orthogonal U, V and diagonal w such that:
//   (this) = U * Diag(w) * V^T
void MatrixRmn::ComputeSVD(
    MatrixRmn &U, VectorRn &w, MatrixRmn &V) const {
  assert(U.NumRows == NumRows &&
         V.NumCols == NumCols &&
         U.NumRows == U.NumCols &&
         V.NumRows == V.NumCols &&
         w.GetLength() ==
             std::min(NumRows, NumCols));

  VectorRn &superDiag =
      VectorRn::GetWorkVector(w.GetLength() - 1);

  // If U is larger than V, copy A into U and compute
  // SVD of A. Otherwise copy A-transpose into V and
  // compute SVD of A^T (essentially the same result).
  MatrixRmn *leftMatrix;
  MatrixRmn *rightMatrix;
  if (NumRows >= NumCols) {
    U.LoadAsSubmatrix(*this);
    leftMatrix  = &U;
    rightMatrix = &V;
  } else {
    V.LoadAsSubmatrixTranspose(*this);
    leftMatrix  = &V;
    rightMatrix = &U;
  }

  // Reduce to bidiagonal form via Householder xforms,
  // then iterate Givens rotations (Golub-Reinsch) to
  // drive superdiagonal entries to zero.
  CalcBidiagonal(
      *leftMatrix, *rightMatrix, w, superDiag);
  ConvertBidiagToDiagonal(
      *leftMatrix, *rightMatrix, w, superDiag);
}

def _extract_with_regex(
    self,
    content: str,
    tokens: list[str],
    language: str,
) -> HandlerResult:
    spans: list[CodeSpan] = []

    import_pattern = _IMPORT_PATTERNS.get(language)
    if import_pattern:
        for match in import_pattern.finditer(content):
            end = content.find("\n", match.end())
            if end == -1:
                end = len(content)
            spans.append(
                CodeSpan(
                    start=match.start(),
                    end=end,
                    role="import",
                    is_structural=True,
                )
            )

    signature_patterns = _SIGNATURE_PATTERNS.get(language, [])
    for pattern in signature_patterns:
        for match in pattern.finditer(content):
            spans.append(
                CodeSpan(
                    start=match.start(),
                    end=match.end(),
                    role="signature",
                    is_structural=True,
                )
            )

    mask = self._spans_to_mask(spans, len(content))

    return HandlerResult(
        mask=StructureMask(tokens=tokens, mask=mask),
        handler_name=self.name,
        confidence=0.7,
        metadata={
            "language": language,
            "parser": "regex",
            "structural_spans": len(spans),
        },
    )

async def join_session(
    self,
    session_id: str,
    agent_did: str,
    actions: list[ActionDescriptor] | None = None,
    sigma_raw: float = 0.0,
    manifest: Any | None = None,
    agent_history: Any | None = None,
) -> ExecutionRing:
    managed = self._get_session(session_id)

    # Step 1: IATP manifest enrichment
    if self.iatp and manifest:
        if isinstance(manifest, dict):
            analysis = self.iatp.analyze_manifest_dict(
                manifest
            )
        else:
            analysis = self.iatp.analyze_manifest(manifest)
        if not actions:
            actions = analysis.actions
        if sigma_raw == 0.0:
            sigma_raw = analysis.sigma_hint
        logger.debug(
            "IATP manifest parsed for %s: ring_hint=%s",
            agent_did, analysis.ring_hint
        )

    # Step 2: Register actions
    if actions:
        managed.reversibility.register_from_manifest(
            actions
        )

    # Step 3: Mode negotiation
    if managed.reversibility.has_non_reversible_actions():
        managed.sso.force_consistency_mode(
            ConsistencyMode.STRONG
        )

    # Step 4: Verify history
    verification = self.verifier.verify(agent_did)

    # Step 5: Resolve effective score
    eff_score = sigma_raw

    if self.nexus and sigma_raw == 0.0:
        eff_score = self.nexus.resolve_sigma(
            agent_did, history=agent_history,
        )
    elif self.nexus and agent_history:
        nexus_sigma = self.nexus.resolve_sigma(
            agent_did, history=agent_history,
        )
        eff_score = min(sigma_raw, nexus_sigma)

    ring = self.ring_enforcer.compute_ring(eff_score)

    if not verification.is_trustworthy:
        ring = ExecutionRing.RING_3_SANDBOX

    managed.sso.join(
        agent_did=agent_did,
        sigma_raw=sigma_raw,
        eff_score=eff_score,
        ring=ring,
    )

    return ring

export function replaceHistoricalToolInputs(
    messages: any[]
): any[] {
    return messages.map((msg) => {
        if (
            msg.role !== "assistant" ||
            !Array.isArray(msg.content)
        ) {
            return msg
        }
        const replacedContent = msg.content
            .map((part: any) => {
                if (part.type === "tool-call") {
                    const toolName = part.toolName
                    if (
                        !part.input ||
                        typeof part.input !== "object" ||
                        Object.keys(part.input).length === 0
                    ) {
                        return null
                    }
                    if (
                        toolName === "display_diagram" ||
                        toolName === "edit_diagram"
                    ) {
                        return {
                            ...part,
                            input: {
                                placeholder:
                                    "[XML content replaced" +
                                    " - see current diagram" +
                                    " XML in system context]",
                            },
                        }
                    }
                }
                return part
            })
            .filter(Boolean)
        return { ...msg, content: replacedContent }
    })
}

'use client'

import {
  useRouter,
  useSearchParams,
  usePathname
} from 'next/navigation'

export type ModalType = 'source' | 'note' | 'insight'

export function useModalManager() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const pathname = usePathname()

  const modalType =
    searchParams?.get('modal') as ModalType | null
  const modalId = searchParams?.get('id')

  const openModal = (type: ModalType, id: string) => {
    const params = new URLSearchParams(
      searchParams?.toString() || ''
    )
    params.set('modal', type)
    params.set('id', id)
    router.push(
      `${pathname}?${params.toString()}`,
      { scroll: false }
    )
  }

  const closeModal = () => {
    const params = new URLSearchParams(
      searchParams?.toString() || ''
    )
    params.delete('modal')
    params.delete('id')
    router.push(
      `${pathname}?${params.toString()}`,
      { scroll: false }
    )
  }

  return {
    modalType,
    modalId,
    openModal,
    closeModal,
    isOpen: !!modalType && !!modalId
  }
}

bool NetworkUtilities::checkIpSubnetFormat(
    const QString &ip)
{
    if (!ip.contains("/"))
        return checkIPv4Format(ip);

    QStringList parts = ip.split("/");
    if (parts.size() != 2)
        return false;

    bool ok;
    int subnet = parts.at(1).toInt(&ok);
    if (subnet >= 0 && subnet <= 32 && ok)
        return checkIPv4Format(parts.at(0));
    else
        return false;
}

bool GraphTracker::hook_allocate(
    const Buffer* buffer) {
    if (hook == nullptr) {
        return false;
    }

    bool hooked = hook->hook_allocate(buffer);
    if (hooked) {
        std::lock_guard<std::mutex> lock(
            hooked_buffers_mutex);
        bool inserted =
            hooked_buffers.insert(buffer).second;
        TT_FATAL(inserted,
            "Can't hook allocation of a buffer "
            "which is already allocated");
    }
    return hooked;
}

bool GraphTracker::hook_deallocate(
    Buffer* buffer) {
    if (hook == nullptr) {
        return false;
    }

    bool hooked = hook->hook_deallocate(buffer);
    if (hooked) {
        std::lock_guard<std::mutex> lock(
            hooked_buffers_mutex);
        auto buffer_it =
            hooked_buffers.find(buffer);
        if (buffer_it == hooked_buffers.end()) {
            log_warning(tt::LogMetal,
                "Can't hook deallocation of a "
                "buffer which allocation "
                "wasn't hooked");
        } else {
            hooked_buffers.erase(buffer_it);
        }
    }
    return hooked;
}

def build_model_step(
    llm_client: LLMClient,
    *,
    system_prompt: str | None = None,
) -> ModelStep:
    def model_step(
        messages: list[dict[str, Any]],
        tools: list[Tool],
        sampling: dict[str, Any],
    ) -> ModelStepResult:
        effective_messages = list(messages)
        if system_prompt and not any(
            m.get("role") == "system"
            for m in effective_messages
        ):
            effective_messages.insert(
                0, {"role": "system", "content": system_prompt}
            )

        tool_dicts = [_tool_to_mcp_dict(t) for t in tools]
        dropped_keys = sorted(
            set(sampling) - _SUPPORTED_SAMPLING_KEYS
        )
        if dropped_keys:
            warnings.warn(
                "Dropping unsupported sampling keys: "
                + ", ".join(dropped_keys),
                RuntimeWarning,
                stacklevel=2,
            )
        filtered_sampling = {
            k: v
            for k, v in sampling.items()
            if k in _SUPPORTED_SAMPLING_KEYS
        }

        response = run_async_safely(
            llm_client.complete_with_tools(
                messages=effective_messages,
                tools=tool_dicts,
                **filtered_sampling,
            )
        )
        return ModelStepResult(response=response)

    return model_step

def probe_command(
    cmd: str,
    args: Sequence[str] = ("--version",),
    timeout: int = 10,
    retries: int = 0,
    package: Optional[str] = None,
) -> ProbeResult:
    path = shutil.which(cmd)
    if not path:
        return ProbeResult("missing")

    last: Optional[ProbeResult] = None
    for _ in range(retries + 1):
        last = _run_once(path, args, timeout, package or cmd)
        if last.ok:
            return last
        if last.status in ("missing", "broken"):
            return last
    return last


def _run_once(
    path: str,
    args: Sequence[str],
    timeout: int,
    package: str,
) -> ProbeResult:
    try:
        r = subprocess.run(
            [path, *args],
            capture_output=True,
            encoding="utf-8",
            errors="replace",
            timeout=timeout,
            env=utf8_subprocess_env(),
        )
    except FileNotFoundError:
        return ProbeResult(
            "broken", hint=reinstall_hint(package)
        )
    except OSError:
        return ProbeResult(
            "broken", hint=reinstall_hint(package)
        )
    except subprocess.TimeoutExpired:
        return ProbeResult(
            "timeout",
            hint=f"`{path}` 响应超时（>{timeout}s）",
        )

    if r.returncode in _BROKEN_EXIT_CODES:
        return ProbeResult(
            "broken", hint=reinstall_hint(package)
        )

    output = (r.stdout or "") + (r.stderr or "")
    if r.returncode != 0:
        return ProbeResult("error", output=output.strip())
    return ProbeResult("ok", output=output.strip())

function buildAgentTargets(
  plugin: ClaudePlugin,
  agents: CodexAgent[],
): Record<string, string> {
  const targets: Record<string, string> = {}
  plugin.agents.forEach((agent, index) => {
    const targetName = agents[index]?.name
    if (!targetName) return
    const category = getAgentCategory(agent)
    const aliases = [
      agent.name,
      normalizeCodexName(agent.name),
      agent.name.startsWith("ce-")
        ? agent.name.slice("ce-".length)
        : "",
      category ? `${category}:${agent.name}` : "",
      category && agent.name.startsWith("ce-")
        ? `${category}:${agent.name.slice("ce-".length)}`
        : "",
      category
        ? `${plugin.manifest.name}:${category}:${agent.name}`
        : "",
      category && agent.name.startsWith("ce-")
        ? `${plugin.manifest.name}:${category}` +
          `:${agent.name.slice("ce-".length)}`
        : "",
    ].filter(Boolean)

    for (const alias of aliases) {
      targets[normalizeCodexName(alias)] = targetName
    }
  })
  return targets
}

function getAgentCategory(agent: ClaudeAgent): string | null {
  const parts = agent.sourcePath.split(path.sep)
  const agentsIndex = parts.lastIndexOf("agents")
  if (agentsIndex === -1) return null
  const next = parts[agentsIndex + 1]
  if (!next || next.endsWith(".md")) return null
  return next
}

function collectCalls(
  node: TSNode,
  result: FileExtraction,
  declByName: Map<string, GraphNode>,
): void {
  if (node.type === "call_expression") {
    const fn = node.childForFieldName("function");
    if (fn !== null && fn.type === "identifier") {
      const target = declByName.get(fn.text);
      const caller = findEnclosingFn(node, declByName);
      if (target !== undefined && caller !== null) {
        result.edges.push({
          source: caller.id,
          target: target.id,
          relation: "calls",
          confidence: "EXTRACTED",
        });
      }
    }
  }
  for (let i = 0; i < node.namedChildCount; i++) {
    const child = node.namedChild(i);
    if (child !== null)
      collectCalls(child, result, declByName);
  }
}

uint32_t PinAnalyzer::estimateBaseT(
    const std::vector<uint32_t>& pulses)
{
    if (pulses.size() < 10) return 0;

    std::vector<uint32_t> v = pulses;
    std::sort(v.begin(), v.end());
    size_t m = std::max<size_t>(8, v.size()/4);
    v.resize(m);
    return medianOf(v);
}

float PinAnalyzer::jitterScorePct(
    const std::vector<uint32_t>& pulses,
    uint32_t ref)
{
    if (pulses.size() < 10 || ref == 0)
        return 100.f;

    std::vector<uint32_t> dev;
    dev.reserve(pulses.size());
    for (auto p : pulses) {
        uint32_t d = (p > ref)
            ? (p - ref) : (ref - p);
        dev.push_back(d);
    }
    uint32_t mad = medianOf(dev);
    float pct = (100.0f * (float)mad) / (float)ref;
    if (pct < 0.f)   pct = 0.f;
    if (pct > 200.f) pct = 200.f;
    return pct;
}

float sigma_to_t(float sigma) override {
    float log_sigma = std::log(sigma);
    std::vector<float> dists;
    dists.reserve(TIMESTEPS);
    for (float log_sigma_val : log_sigmas) {
        dists.push_back(log_sigma - log_sigma_val);
    }
    int low_idx = 0;
    for (size_t i = 0; i < TIMESTEPS; i++) {
        if (dists[i] >= 0) {
            low_idx++;
        }
    }
    low_idx = std::min(
        std::max(low_idx - 1, 0), TIMESTEPS - 2);
    int high_idx = low_idx + 1;
    float low  = log_sigmas[low_idx];
    float high = log_sigmas[high_idx];
    float w = (low - log_sigma) / (low - high);
    w = std::max(0.f, std::min(1.f, w));
    float t = (1.0f - w) * low_idx + w * high_idx;
    return t;
}
